def run_program(program):
    pc = 0    # 프로그램 카운터: 다음에 실행할 명령의 주소
    acc = 0   # 누산기: 연산 결과를 저장
    memory = {}
    trace = []

    while pc < len(program):
        instruction = program[pc]  # 1. 명령어 인출(fetch)
        op = instruction[0]        # 2. 명령어 해석(decode)

        if op == "LOAD":
            acc = instruction[1]             # 3~4. 피연산자 인출 및 실행
        elif op == "ADD":
            acc += instruction[1]
        elif op == "SUB":
            acc -= instruction[1]
        elif op == "STORE":
            memory[instruction[1]] = acc     # 5. 결과 저장
        elif op == "HALT":
            trace.append((pc, op, acc))
            break

        trace.append((pc, op, acc))
        pc += 1  # 다음 명령어로 이동(PC 증가)

    return acc, memory, trace

program = [("LOAD", 5), ("ADD", 3), ("SUB", 2), ("STORE", 0), ("HALT",)]
acc, memory, trace = run_program(program)

for pc, op, val in trace:
    print(f"PC={pc}: {op} 실행 후 누산기={val}")

assert acc == 6 and memory[0] == 6
print("명령어 사이클 시뮬레이션 결과: 누산기=6, 메모리[0]=6 확인")
